layui.use(["form","layer"],function(){let form=layui.form;let layer=layui.layer;form.verify({name:function(b,a){let nameRex=/^[\w\W\s\u4e00-\u9fcc]{2,20}$/;if(!nameRex.test(b)){return"技能名只能为2-20个字符"}},owner:function(b,a){let ownerRex=/^[\w\W\s\u4e00-\u9fcc]{2,20}$/;if(!ownerRex.test(b)){return"技能所有者只能为2-20个字符"}}});form.on("submit(form-skill-submit)",function(a){let skill=a.field;layer.confirm("确认提交？",{btn:["确认","取消"]},function(b){$.ajax({url:"/skill",data:{name:skill.name,owner:skill.owner,percent:skill.percent},method:"POST",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false})});